import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function ProblemList() {
  const [problems, setProblems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filter, setFilter] = useState({
    category: '',
    difficulty: ''
  });
  const [pagination, setPagination] = useState({
    page: 1,
    limit: 10,
    total: 0
  });
  const navigate = useNavigate();

  useEffect(() => {
    const controller = new AbortController();
    
    async function fetchProblems() {
      setLoading(true);
      setError(null);
      try {
        const token = localStorage.getItem('token');
        const response = await axios.get('/api/problems', {
          headers: token ? { Authorization: `Bearer ${token}` } : {},
          params: {
            search: searchTerm || undefined,
            category: filter.category || undefined,
            difficulty: filter.difficulty || undefined,
            page: pagination.page,
            limit: pagination.limit
          },
          signal: controller.signal
        });
        
        setProblems(response.data.problems);
        setPagination(response.data.pagination);
      } catch (err) {
        if (err.name !== 'CanceledError') {
          setError(err.response?.data?.message || err.message || 'Failed to fetch problems');
        }
      } finally {
        setLoading(false);
      }
    }

    const timer = setTimeout(() => {
      fetchProblems();
    }, 500);

    return () => {
      controller.abort();
      clearTimeout(timer);
    };
  }, [searchTerm, filter, pagination.page]);

  const handleProblemClick = (id) => {
    navigate(`/problems/${id}`);
  };

  const getDifficultyColor = (difficulty) => {
    switch (difficulty.toLowerCase()) {
      case 'easy': return '#4CAF50';
      case 'medium': return '#FFC107';
      case 'hard': return '#F44336';
      default: return '#9E9E9E';
    }
  };

  if (loading) return <div className="loading-spinner">Loading...</div>;
  
  if (error) return (
    <div className="error-message">
      <h3>Error Loading Problems</h3>
      <p>{error}</p>
    </div>
  );

  return (
    <div className="problem-list-container">
      <h1>Problems</h1>
      
      <div className="filter-controls">
        <input
          type="text"
          placeholder="Search problems..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        
        <select
          value={filter.category}
          onChange={(e) => setFilter({...filter, category: e.target.value})}
        >
          <option value="">All Categories</option>
          <option value="array">Array</option>
          <option value="string">String</option>
          <option value="linked-list">Linked List</option>
          <option value="tree">Tree</option>
          <option value="graph">Graph</option>
          <option value="dynamic-programming">Dynamic Programming</option>
        </select>
        
        <select
          value={filter.difficulty}
          onChange={(e) => setFilter({...filter, difficulty: e.target.value})}
        >
          <option value="">All Difficulties</option>
          <option value="easy">Easy</option>
          <option value="medium">Medium</option>
          <option value="hard">Hard</option>
        </select>
      </div>

      {problems.length === 0 ? (
        <div className="no-problems">No problems found matching your criteria.</div>
      ) : (
        <>
          <div className="problems-grid">
            {problems.map((problem) => (
              <div
                key={problem._id}
                className="problem-card"
                onClick={() => handleProblemClick(problem._id)}
              >
                <h3>{problem.title}</h3>
                <div className="problem-meta">
                  <span className="problem-category">{problem.category}</span>
                  <span 
                    className="problem-difficulty"
                    style={{ backgroundColor: getDifficultyColor(problem.difficulty) }}
                  >
                    {problem.difficulty}
                  </span>
                </div>
                <div 
                  className="problem-description"
                  dangerouslySetInnerHTML={{ __html: problem.description }}
                />
              </div>
            ))}
          </div>
          
          <div className="pagination-controls">
            <button
              disabled={pagination.page === 1}
              onClick={() => setPagination({...pagination, page: pagination.page - 1})}
            >
              Previous
            </button>
            <span>Page {pagination.page} of {pagination.pages}</span>
            <button
              disabled={pagination.page >= pagination.pages}
              onClick={() => setPagination({...pagination, page: pagination.page + 1})}
            >
              Next
            </button>
          </div>
        </>
      )}
    </div>
  );
}

export default ProblemList;
